// ═══ RATIO LEARN DATA (19 ratios × 3 steps) ═══

export interface RatioLearnItem {
  id: string;
  cat: 'Profitability' | 'Investment' | 'Liquidity' | 'Gearing';
  name: string;
  steps: { label: string; html: string }[];
}

export const RATIO_LEARN_DATA: RatioLearnItem[] = [
  { id: 'roce', cat: 'Profitability', name: 'ROCE (Return on Capital Employed)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> The return the company generates on ALL the money invested in it — both shareholders\' funds and long-term borrowings. It is the single most important ratio for measuring overall company performance.</div><div class="lr-norm">Ideal: higher than the risk-free rate (2-3%) and higher than prior year</div><div class="lr-text"><strong>Marking scheme language:</strong> "The return on capital employed measures the efficiency with which management uses the resources available to it."</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">ROCE = Operating Profit / Capital Employed \× 100<br><br>Operating Profit = Net Profit + Interest<br>Capital Employed = Total Assets \− Current Liabilities (= bottom of BS)</div><div class="lr-example"><strong>2025 Technik plc:</strong><br>Operating Profit = 232,000 + 14,000 = \€246,000<br>Capital Employed = \€1,885,000<br>ROCE = 246,000 \÷ 1,885,000 \× 100 = <strong>13.05%</strong><br>Prior year: 10.8%</div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "The ROCE has improved from 10.8% to 13.05%. This is a satisfactory return and is well above the risk-free rate. Management is using the company\'s resources more efficiently than last year. This would encourage investors." <em>(4 marks: state ratio, compare to prior, comment on adequacy, link to management efficiency)</em></div>' },
    ]
  },
  { id: 'rosf', cat: 'Profitability', name: 'ROSF (Return on Equity)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> The return earned specifically for the ORDINARY shareholders, after deducting preference dividends. Shows how effectively the company uses shareholders\' money.</div><div class="lr-norm">Ideal: higher than ROCE (shareholders take more risk so expect more return)</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">ROSF = (PAT \− Pref Dividend) / (Ord Shares + Reserves) \× 100<br><br>PAT = Profit After Tax (or Net Profit if no tax given)<br>Reserves = P&L Balance (retained profits)</div><div class="lr-example"><strong>2022 Watson plc:</strong><br>PAT = 41,000. Pref Div = 6% \× 150,000 = 9,000<br>Equity = 365,000 + 101,000 = 466,000<br>ROSF = (41,000 \− 9,000) \÷ 466,000 \× 100 = <strong>6.87%</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "The return on shareholders\' funds has decreased from 12% to 6.87%. This is a poor return for ordinary shareholders and is barely above what could be earned in a risk-free deposit account. Shareholders may question management\'s ability to generate adequate returns."</div>' },
    ]
  },
  { id: 'gpm', cat: 'Profitability', name: 'Gross Profit Margin',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> The profit earned from trading BEFORE expenses are deducted. Shows how effectively the company manages its cost of sales (purchasing, stock, pricing).</div><div class="lr-norm">Varies by sector. Manufacturing: 30-40%. Retail: 20-30%. Service: 50%+</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Gross Profit Margin = Gross Profit / Sales \× 100<br><br>Gross Profit = Sales \− Cost of Sales</div><div class="lr-example"><strong>If Sales = \€1,898,000 and COGS = \€1,440,000:</strong><br>GP = 1,898,000 \− 1,440,000 = 458,000<br>GP% = 458,000 \÷ 1,898,000 \× 100 = <strong>24.13%</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>Reasons for decline:</strong> Purchase prices increased and not passed on. Stock theft. Incorrect stock valuation. Slow-moving/obsolete stock. <strong>Improvements:</strong> Increase selling prices. Find cheaper suppliers. Improve stock control. Reduce wastage.</div>' },
    ]
  },
  { id: 'npm', cat: 'Profitability', name: 'Net Profit Margin',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> The profit remaining AFTER all operating expenses are deducted. Shows how well the company controls its total cost base. A falling NPM with stable GPM suggests expenses are rising.</div><div class="lr-norm">Varies. IT: 15-25%. Retail: 3-8%. Construction: 5-12%</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Net Profit Margin = Net Profit / Sales \× 100</div><div class="lr-example">Net Profit \€232,000, Sales \€1,898,000<br>NPM = 232,000 \÷ 1,898,000 \× 100 = <strong>12.22%</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> Compare NPM to GPM. If GPM is stable but NPM is falling, operating expenses are growing too fast. Recommend management review selling and admin expenses and stay within budget.</div>' },
    ]
  },
  { id: 'eps', cat: 'Investment', name: 'Earnings Per Share (EPS)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> The profit earned per ordinary share. This is the key figure used by investors and is the basis for the P/E ratio. <strong>Always deduct preference dividends first.</strong></div><div class="lr-norm">Answer in CENT (not euro). Higher = better for investors</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">EPS = (PAT \− Pref Dividend) / No. of Ordinary Shares<br><br>Answer in cent: multiply result by 100 if needed</div><div class="lr-example"><strong>2025 Technik plc:</strong><br>PAT = 232,000. Pref Div = 6% \× 550,000 = 33,000<br>Ord Shares = 900,000<br>EPS = (232,000 \− 33,000) \÷ 900,000 = <strong>22.11c</strong><br>Prior year: 30c</div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "EPS has decreased from 30c to 22.11c. This means each ordinary share is earning less profit than last year. However, the company may have issued more shares during the year which would dilute EPS. Shareholders would be concerned about this decline."</div>' },
    ]
  },
  { id: 'pe', cat: 'Investment', name: 'P/E Ratio (Price Earnings)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> How many years it would take to recoup the market price of one share at the current earnings level. A HIGH P/E means investors expect future growth. A LOW P/E may indicate the company is undervalued or in decline.</div><div class="lr-norm">Answer in YEARS. Both values must be in cent. Typical: 8-15 years</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">P/E Ratio = Market Price per Share / EPS<br><br>Both must be in same units (cent)</div><div class="lr-example"><strong>2025 Technik plc:</strong><br>Market Price = \€1.60 = 160c<br>EPS = 22.11c<br>P/E = 160 \÷ 22.11 = <strong>7.24 years</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "The P/E ratio of 7.24 means it would take approximately 7 years to recover the price paid for the share at the current level of earnings. This is a reasonable figure. A lower P/E than last year may suggest the market expects slower growth."</div>' },
    ]
  },
  { id: 'dps', cat: 'Investment', name: 'Dividend Per Share (DPS)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> The actual cash returned to each ordinary shareholder. Answer in <strong>cent</strong>. Always deduct preference dividends from total dividends first.</div><div class="lr-norm">Answer in CENT</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">DPS = Ordinary Dividends / No. of Ordinary Shares<br><br>Ordinary Dividends = Total Dividends Paid \− Preference Dividends</div><div class="lr-example"><strong>2025 Technik:</strong> Total div = 122,000. Pref = 33,000. Ord = 89,000<br>DPS = 89,000 \÷ 900,000 = <strong>9.89c</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>Compare to prior year DPS.</strong> Increasing DPS is positive for shareholders. If DPS is rising but EPS is falling, management may be paying unsustainable dividends.</div>' },
    ]
  },
  { id: 'divcover', cat: 'Investment', name: 'Dividend Cover',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> How many times the ordinary dividend could be paid from available earnings. High cover = safe, sustainable dividends. Low cover = dividends may need to be cut.</div><div class="lr-norm">Ideal: at least 2 times. Below 1.5 = concerning</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Dividend Cover = EPS / DPS<br><br>OR: (PAT \− Pref Div) / Ordinary Dividends</div><div class="lr-example"><strong>2025 Technik:</strong> EPS = 22.11c, DPS = 9.89c<br>Cover = 22.11 \÷ 9.89 = <strong>2.24 times</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "Dividend cover of 2.24 times is adequate. The company can comfortably pay its current level of dividends and still retain profits for reinvestment. A cover below 2 would indicate dividends may be at risk."</div>' },
    ]
  },
  { id: 'divyield', cat: 'Investment', name: 'Dividend Yield',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> The annual return a shareholder receives as a percentage of the market price they paid. Compare to interest on deposits. Low yield may still be acceptable if the company is growing (capital gains instead).</div><div class="lr-norm">Compare to risk-free rate (2-3%). DPS and Market Price both in cent</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Dividend Yield = DPS / Market Price \× 100<br><br>Both in cent</div><div class="lr-example"><strong>2023 O\'Malley:</strong> DPS = 8c, Market = 130c<br>Yield = 8 \÷ 130 \× 100 = <strong>6.15%</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "The dividend yield of 6.15% is above the risk-free rate and represents a reasonable cash return for shareholders. This compares favourably with bank deposit rates."</div>' },
    ]
  },
  { id: 'current', cat: 'Liquidity', name: 'Current Ratio',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> Can the company pay its short-term debts as they fall due? Shows the relationship between current assets (stock, debtors, cash) and current liabilities (creditors, bank OD, tax due).</div><div class="lr-norm">Ideal: 1.5:1 to 2:1. Below 1:1 = serious liquidity concern</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Current Ratio = Current Assets / Current Liabilities<br><br>Express as X:1</div><div class="lr-example"><strong>2025 Technik:</strong> CA = 369,500. CL = 184,500<br>Current Ratio = 369,500 \÷ 184,500 = <strong>2.00:1</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "The current ratio of 2:1 is in line with the accepted norm. The company can meet its short-term obligations comfortably. However, an excessively high current ratio (e.g. 5:1) would suggest resources are not being used efficiently."</div>' },
    ]
  },
  { id: 'acidtest', cat: 'Liquidity', name: 'Acid Test (Quick Ratio)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> Same as current ratio but EXCLUDES stock (which may take time to sell). A more stringent test of immediate liquidity.</div><div class="lr-norm">Ideal: 1:1. Below 0.8:1 = liquidity risk. Some questions call it "Quick Ratio"</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Acid Test = (Current Assets \− Closing Stock) / Current Liabilities</div><div class="lr-example"><strong>If CA = 369,500, Stock = 127,500, CL = 184,500:</strong><br>Acid Test = (369,500 \− 127,500) \÷ 184,500 = <strong>1.31:1</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "The acid test of 1.31:1 exceeds the accepted norm of 1:1. Even without selling its stock, the company can meet its immediate liabilities. This is a strong liquidity position."<br><br><strong>If below 1:1:</strong> "The company may struggle to pay creditors on time. Management should consider improving debtor collection, reducing stock levels, or negotiating longer credit terms."</div>' },
    ]
  },
  { id: 'stockturn', cat: 'Liquidity', name: 'Stock Turnover (Rate of)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> How quickly stock is sold and replaced. A high rate means stock sells fast (good for supermarkets). A low rate means stock sits on shelves (bad for cash flow).</div><div class="lr-norm">Varies by sector. Supermarket: 20+. Jeweller: 2-4. Answer in TIMES</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Stock Turnover = Cost of Sales / Average Stock<br><br>Average Stock = (Opening + Closing) / 2<br><br>REVERSE WORKING: if given rate, find Opening Stock:<br>Rate = COS \÷ Avg Stock \\u2192 Avg Stock = COS \÷ Rate \\u2192 Opening = (Avg \× 2) \− Closing</div><div class="lr-example"><strong>2023 O\'Malley (reverse):</strong> Rate = 14, COS = 560,000, Closing = 42,000<br>Avg = 560,000 \÷ 14 = 40,000<br>Opening = (40,000 \× 2) \− 42,000 = <strong>\€38,000</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> Compare to prior year. Increasing rate = selling faster = positive. Decreasing = stock is moving slower, possibly obsolete or overordered. Compare to sector norms.</div>' },
    ]
  },
  { id: 'debtdays', cat: 'Liquidity', name: 'Debtors Days (Collection Period)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> How long customers take to pay. Shorter = better cash flow. If increasing, the company is giving too much credit or not chasing debts effectively.</div><div class="lr-norm">Answer in MONTHS (multiply by 12). Sometimes asked to find CASH SALES</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Debtors Days = Debtors / Credit Sales \× 12 (months)<br><br>REVERSE: if given the period, find credit/cash sales:<br>Credit Sales = Debtors \× 12 \÷ Period<br>Cash Sales = Total Sales \− Credit Sales</div><div class="lr-example"><strong>2025 Technik:</strong> Debtors = 103,000. Period = 2 months.<br>Credit Sales = 103,000 \× 12 \÷ 2 = 618,000<br>Cash Sales = 1,898,000 \− 618,000 = <strong>\€1,280,000</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "The debtor collection period should be shorter than the creditor payment period. If debtors pay in 3 months but creditors are paid in 1.5 months, there is a cash flow gap that must be financed."</div>' },
    ]
  },
  { id: 'creddays', cat: 'Liquidity', name: 'Creditors Days (Payment Period)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> How long the company takes to pay its suppliers. Longer = holding cash longer (good for cash flow). But paying too slowly risks losing supplier goodwill and discounts.</div><div class="lr-norm">Answer in MONTHS. Should be > Debtors Days for positive cash cycle</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Creditors Days = Creditors / Credit Purchases \× 12 (months)<br><br>REVERSE: if given period, find credit/cash purchases:<br>Credit Purchases = Creditors \× 12 \÷ Period<br>Cash Purchases = Total Purchases \− Credit Purchases</div><div class="lr-example"><strong>2022 Watson:</strong> Creditors = 21,000. Period = 3.6 months.<br>Credit Purchases = 21,000 \× 12 \÷ 3.6 = 70,000<br>Total = 70,000 \÷ 80% = 87,500<br>Cash = 20% \× 87,500 = <strong>\€17,500</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> Compare debtors days to creditors days. If debtors collect in 2 months and creditors are paid in 3 months, the cash cycle is positive. If reversed, the company faces liquidity pressure.</div>' },
    ]
  },
  { id: 'gearing', cat: 'Gearing', name: 'Gearing Ratio (Capital Gearing)',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> What proportion of the company\'s finance comes from borrowings (debt) versus equity. High gearing = more debt = more financial risk because interest MUST be paid regardless of profits.</div><div class="lr-norm">Below 50% = low geared (safe). Above 50% = high geared (risky)</div><div class="lr-text"><strong>KEY:</strong> Preference shares count as DEBT (they have a fixed dividend commitment).</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Gearing = (Debentures + Pref Share Capital) / Capital Employed \× 100</div><div class="lr-example"><strong>2022 Watson:</strong><br>Debt = 500,000 (debentures) + 150,000 (pref shares) = 650,000<br>CE = 1,116,000<br>Gearing = 650,000 \÷ 1,116,000 \× 100 = <strong>58.24%</strong><br>Prior year: 60%</div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For debenture holders:</strong> "The gearing of 58.24% is above 50%, making this a highly geared company. Debenture holders should be cautious as a high proportion of the company\'s capital is borrowed."<br><br><strong>For bank manager:</strong> "If a new loan of \€500,000 is granted, gearing would increase to (650,000 + 500,000) \÷ (1,116,000 + 500,000) = 71.2%. This is dangerously high. I would NOT recommend granting the loan." <em>(ALWAYS recalculate gearing with the proposed loan included)</em></div>' },
    ]
  },
  { id: 'intcover', cat: 'Gearing', name: 'Interest Cover',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> How many times the company can pay its interest bill from operating profits. The higher the better. Below 3 times is a warning sign that the company may struggle to service its debt.</div><div class="lr-norm">Ideal: at least 3-4 times. Below 2 = serious risk for lenders</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Interest Cover = Operating Profit / Interest<br><br>Operating Profit = Net Profit + Interest</div><div class="lr-example"><strong>2025 Technik:</strong><br>OP = 232,000 + 14,000 = 246,000<br>Interest = 14,000<br>Cover = 246,000 \÷ 14,000 = <strong>17.57 times</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For debenture holders:</strong> "Interest cover of 17.57 times is excellent. The company can comfortably pay its interest obligations many times over from operating profits. Debenture holders should be satisfied with this level of security."<br><br><strong>Warning level:</strong> "Interest cover has fallen from 11 times to 2.67 times. The company is barely earning enough to pay its interest. This is a very concerning trend for lenders."</div>' },
    ]
  },
  { id: 'recoup', cat: 'Investment', name: 'Period to Recoup at Payout Rate',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> How many years it would take to get your money back from dividends alone (ignoring any change in share price). Unlike P/E which uses earnings, this uses the actual CASH dividend paid.</div><div class="lr-norm">Answer in YEARS. Usually higher than P/E ratio (not all earnings are paid out)</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Period to Recoup = Market Price / DPS<br><br>Both in cent</div><div class="lr-example"><strong>2025 Murphy (mock):</strong> Market = 145c, DPS = 3.41c<br>Period = 145 \÷ 3.41 = <strong>42.52 years</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>For the report:</strong> "At the current dividend payout rate, it would take 42.52 years to recover the market price of the share. This is a very long period. However, shareholders also benefit from any increase in the market value of the share over time."</div>' },
    ]
  },
  { id: 'markup', cat: 'Profitability', name: 'Mark-Up',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> The profit added onto the cost price to arrive at the selling price. Different from margin: mark-up is profit as a % of COST, margin is profit as a % of SALES.</div><div class="lr-norm">Mark-up is always HIGHER than the corresponding margin</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Mark-Up = Gross Profit / Cost of Sales \× 100</div><div class="lr-example">GP = 458,000, COS = 1,440,000<br>Mark-up = 458,000 \÷ 1,440,000 \× 100 = <strong>31.81%</strong></div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>Note:</strong> Mark-up is less commonly examined than GP Margin but appears as a working in some questions. If given a mark-up of 50%, the margin is 33.3%. If given a margin of 25%, the mark-up is 33.3%.</div>' },
    ]
  },
  { id: 'totalexp', cat: 'Profitability', name: 'Total Expenses / Sales %',
    steps: [
      { label: 'Definition', html: '<div class="lr-text"><strong>What it measures:</strong> What percentage of sales revenue is consumed by operating expenses. Lower = more efficient cost control. Rising expenses % with stable sales = falling profitability.</div><div class="lr-norm">Lower is better. Watch for year-on-year trends</div>' },
      { label: 'Formula + Example', html: '<div class="lr-formula">Total Expenses / Sales = Total Expenses / Sales \× 100</div>' },
      { label: 'Interpretation', html: '<div class="lr-interp"><strong>This ratio rarely appears as a standalone calculation but is useful in the report commentary.</strong> If expenses as a % of sales are rising, recommend management review cost control measures.</div>' },
    ]
  },
];

